create table dirkspzm32.s_smithuis_send_bew (
    firma_nr        number(3, 0),
    herkunft        varchar2(3 char),
    tabelle         varchar2(7 char),
    auf_id          number(*, 0),
    status          varchar2(3 char),
    aktion          varchar2(3 char),
    leitzahl        number(*, 5),
    fa_ag           number(*, 0),
    fa_upos         number(*, 0),
    ma_status       varchar2(1 char),
    ma_s_grund      number(3, 0),
    ma_id           varchar2(10 char),
    lte_nr          varchar2(20 char),
    lhm_nr          varchar2(20 char),
    lagerort        varchar2(10 char),
    zlagerort       varchar2(10 char),
    menge_soll      number(*, 3),
    menge           number(*, 3),
    menge_b         number(*, 3),
    schrott         number(*, 3),
    r_menge         number(*, 3),
    r_menge_b       number(*, 3),
    r_schrott       number(*, 3),
    me              varchar2(3 char),
    stoerzeit_ist   number(*, 12),
    ruestzeit_ist   number(*, 12),
    prodzeit_ist    number(*, 12),
    ext_lief_nr     varchar2(20 char),
    ext_lief_pos    varchar2(5 char),
    ext_best_nr     varchar2(20 char),
    ext_best_pos    varchar2(5 char),
    charge          varchar2(60 char),
    serie           varchar2(20 char),
    arbeitsplatz_id varchar2(20 char),
    ist_bestand     number(*, 5),
    artikel         varchar2(30 char),
    b_datum         varchar2(19 char),
    ts              number(*, 0) not null enable,
    brutto_kg       number(*, 6),
    ret_code        varchar2(20 char),
    cycle           number(*, 5)
);

alter table dirkspzm32.s_smithuis_send_bew
    add constraint pk_s_smithuis_send_bew primary key ( ts )
        using index enable;


